long long solve(vector<long long> nums) {
    int n = nums.size();
    long long max_sum = 0;

    // Iterate over all possible masks for A and C (B is the rest)
    // Since each element can be in A, B, or C, there are 3^n possibilities
    // But with n up to 19, 3^19 is too large (1.16e9), so we need a smarter approach

    // However, given the constraints, we can use bitmask for A and C, but it's still O(4^n)
    // But 4^19 is 2^38 which is too large

    // Alternative approach: realize that the optimal solution is to put each element in one of the three groups
    // and the maximum is achieved when each element is in the group that maximizes its contribution

    // But XOR and AND are not associative in the same way, so we can't simply assign each element to the best group

    // Given the small n (up to 19), we can use a backtracking approach to try all possible assignments

    // We'll represent the assignment of each element to A (0), B (1), or C (2)
    // Then compute the XOR(A), AND(B), XOR(C) for each assignment

    // Since 3^19 is about 1.16 billion, it's feasible with optimizations

    // To optimize, we can process the assignments in a way that allows early termination or memoization

    // But for simplicity, we'll proceed with a backtracking approach

    // The backtracking function will track:
    // - current index
    // - current XOR of A
    // - current AND of B
    // - current XOR of C
    // - and update the max_sum accordingly

    // We'll use a recursive function to explore all possibilities

    function<void(int, long long, long long, long long)> backtrack;
    backtrack = [&](int index, long long xor_a, long long and_b, long long xor_c) {
        if (index == n) {
            long long sum = xor_a + and_b + xor_c;
            if (sum > max_sum) {
                max_sum = sum;
            }
            return;
        }

        // Assign current element to A
        backtrack(index + 1, xor_a ^ nums[index], and_b, xor_c);

        // Assign current element to B
        long long new_and_b = (and_b == 0 && index == 0) ? nums[index] : (and_b & nums[index]);
        backtrack(index + 1, xor_a, new_and_b, xor_c);

        // Assign current element to C
        backtrack(index + 1, xor_a, and_b, xor_c ^ nums[index]);
    };

    backtrack(0, 0, 0, 0);

    return max_sum;
}
